- **GitHub Repository**: shelfio/jest-mongodb
  - Latest Version: Check GitHub page for the latest release.
  - Installation:
    ```bash
    npm install --save-dev jest-mongodb
    ```
  - Usage Example:
    ```javascript
    const { MongoMemoryServer } = require('mongodb-memory-server');
    const mongoose = require('mongoose');

    let mongoServer;

    beforeAll(async () => {
      mongoServer = await MongoMemoryServer.create();
      const uri = mongoServer.getUri();

      await mongoose.connect(uri, { useNewUrlParser: true, useUnifiedTopology: true });
    });

    afterAll(async () => {
      await mongoose.connection.close();
      await mongoServer.stop();
    });
    ```

- **Using with Jest**:
  - Global Setup/Teardown Example:
    ```javascript
    // jest.config.js
    module.exports = {
      globalSetup: './setupTests.js',
      globalTeardown: './teardownTests.js',
    };
    ```
  - Async Test Environment Example:
    ```javascript
    // setupTests.js
    const { MongoMemoryServer } = require('mongodb-memory-server');
    const mongoose = require('mongoose');

    let mongoServer;

    module.exports = async () => {
      mongoServer = await MongoMemoryServer.create();
      const uri = mongoServer.getUri();

      await mongoose.connect(uri, { useNewUrlParser: true, useUnifiedTopology: true });
    };
    ```

- **In-Memory MongoDB for Testing**:
  - Key Config Options:
    ```javascript
    const server = new MongoMemoryServer({
      binary: {
        version: '4.4.6', // Specify the desired MongoDB version
      },
      instance: {
        dbName: 'testdb', // Specify the database name
      },
    });
    ```
  - Usage Example:
    ```javascript
    const { MongoClient } = require('mongodb');

    async function run() {
      const uri = await server.getUri();
      const client = new MongoClient(uri);

      try {
        await client.connect();
        const database = client.db('testdb');
        const collection = database.collection('users');

        // Perform operations on the collection
      } finally {
        await client.close();
        await server.stop();
      }
    }

    run().catch(console.dir);
    ```
